#!/bin/bash
find frontend/src -type f -name "*.jsx" -print0 | xargs -0 sed -i '' -e 's/bg-\[var(--neo-yellow)\]/bg-neo-yellow/g' -e 's/bg-\[var(--neo-mint)\]/bg-neo-mint/g' -e 's/bg-\[var(--neo-red)\]/bg-neo-red/g' -e 's/bg-\[var(--neo-blue)\]/bg-neo-blue/g' -e 's/bg-\[var(--neo-surface)\]/bg-neo-surface/g' -e 's/bg-\[var(--neo-surface-high)\]/bg-neo-surface-high/g' -e 's/bg-\[var(--neo-surface-muted)\]/bg-neo-surface-muted/g' -e 's/bg-\[var(--neo-bg)\]/bg-neo-bg/g' -e 's/text-\[var(--neo-text)\]/text-neo-text/g' -e 's/text-\[var(--neo-text-muted)\]/text-neo-text-muted/g' -e 's/text-\[var(--neo-blue)\]/text-neo-blue/g' -e 's/text-\[var(--neo-red)\]/text-neo-red/g' -e 's/text-\[var(--neo-mint)\]/text-neo-mint/g' -e 's/text-\[var(--neo-yellow)\]/text-neo-yellow/g' -e 's/border-\[var(--neo-border)\]/border-neo-border/g' -e 's/fill-\[var(--neo-yellow)\]/fill-neo-yellow/g' -e 's/fill-\[var(--neo-blue)\]/fill-neo-blue/g'
